function solve(prices: number[], strategy: number[], k: number): number {
    let maxProfit = 0;
    const n = prices.length;

    // Calculate the original profit
    let profit = 0;
    for (let i = 0; i < n; i++) {
        profit += strategy[i] * prices[i];
    }
    maxProfit = profit;

    // Try to modify each possible continuous k-length subarray
    for (let i = 0; i <= n - k; i++) {
        // Calculate the profit change if we modify the subarray [i, i+k-1]
        let change = 0;
        // For the first k/2 elements, change from -1 to 0 (buy to hold)
        for (let j = 0; j < k / 2; j++) {
            change += (0 - strategy[i + j]) * prices[i + j];
        }
        // For the next k/2 elements, change from 1 to 0 (sell to hold)
        for (let j = k / 2; j < k; j++) {
            change += (0 - strategy[i + j]) * prices[i + j];
        }
        // Update maxProfit if this modification gives a higher profit
        maxProfit = Math.max(maxProfit, profit + change);
    }

    return maxProfit;
}

